## Implementation: agent-hub-store.ts

Create a feature-local Zustand store (NOT added to the global AppState). This follows the existing pattern of `useAgentDialog` in `features/agent-settings/model/use-agent-dialog.ts`.

```typescript
// apps/client/src/layers/features/agent-hub/model/agent-hub-store.ts

import { create } from 'zustand';
import { devtools } from 'zustand/middleware';

export type AgentHubTab =
  | 'overview'
  | 'personality'
  | 'sessions'
  | 'channels'
  | 'tasks'
  | 'tools';

interface AgentHubState {
  /** Which hub tab is currently active. */
  activeTab: AgentHubTab;
  setActiveTab: (tab: AgentHubTab) => void;

  /**
   * The agent path being viewed in the hub. When null, falls back to
   * selectedCwd from the app store (the currently active agent).
   */
  agentPath: string | null;
  setAgentPath: (path: string | null) => void;

  /** Open the hub for a specific agent, optionally on a specific tab. */
  openHub: (agentPath: string, tab?: AgentHubTab) => void;
}

export const useAgentHubStore = create<AgentHubState>()(
  devtools(
    (set) => ({
      activeTab: 'overview',
      setActiveTab: (tab) => set({ activeTab: tab }),

      agentPath: null,
      setAgentPath: (path) => set({ agentPath: path }),

      openHub: (agentPath, tab) =>
        set({
          agentPath,
          activeTab: tab ?? 'overview',
        }),
    }),
    { name: 'agent-hub' }
  )
);
```

## Implementation: agent-hub-context.tsx

Create a React context that mirrors the existing `AgentDialogContextValue` interface from `features/agent-settings/model/agent-dialog-context.tsx`. This enables reuse of the existing tab components without modification.

```typescript
// apps/client/src/layers/features/agent-hub/model/agent-hub-context.tsx

import { createContext, useContext, type ReactNode } from 'react';
import type { AgentManifest } from '@dorkos/shared/mesh-schemas';

/**
 * Shape of the shared state plumbed into all Agent Hub tab components via React Context.
 *
 * Mirrors AgentDialogContextValue to enable reuse of existing tab components
 * (IdentityTab, PersonalityTab, ToolsTab, ChannelsTab) without modification.
 */
export interface AgentHubContextValue {
  agent: AgentManifest;
  projectPath: string;
  onUpdate: (updates: Partial<AgentManifest>) => void;
  onPersonalityUpdate: (
    updates: Partial<AgentManifest> & { soulContent?: string; nopeContent?: string }
  ) => void;
}

const AgentHubContext = createContext<AgentHubContextValue | undefined>(undefined);

/**
 * Provides shared agent state to all Agent Hub tab components.
 *
 * @param value - The context value containing the agent and callbacks.
 * @param children - React subtree (the hub content).
 */
export function AgentHubProvider({
  value,
  children,
}: {
  value: AgentHubContextValue;
  children: ReactNode;
}) {
  return <AgentHubContext.Provider value={value}>{children}</AgentHubContext.Provider>;
}

/**
 * Reads shared agent state from the nearest `AgentHubProvider`.
 *
 * @returns The current `AgentHubContextValue`.
 * @throws {Error} When called outside an `AgentHubProvider`.
 */
export function useAgentHubContext(): AgentHubContextValue {
  const ctx = useContext(AgentHubContext);
  if (!ctx) throw new Error('useAgentHubContext must be used within an AgentHubProvider');
  return ctx;
}
```

