## Component: AgentHub.tsx (Hub Shell)

Create `apps/client/src/layers/features/agent-hub/ui/AgentHub.tsx`:

```typescript
import { useAppStore } from '@/layers/shared/model';
import { useCurrentAgent, useUpdateAgent } from '@/layers/entities/agent';
import { useAgentHubStore, type AgentHubTab } from '../model/agent-hub-store';
import { AgentHubProvider } from '../model/agent-hub-context';
import { AgentHubHeader } from './AgentHubHeader';
import { AgentHubNav } from './AgentHubNav';
import { AgentHubContent } from './AgentHubContent';
import { NoAgentSelected } from './NoAgentSelected';
import { AgentNotFound } from './AgentNotFound';
import type { AgentManifest } from '@dorkos/shared/mesh-schemas';

export function AgentHub() {
  const hubAgentPath = useAgentHubStore((s) => s.agentPath);
  const selectedCwd = useAppStore((s) => s.selectedCwd);
  const effectivePath = hubAgentPath ?? selectedCwd;
  const { data: agent } = useCurrentAgent(effectivePath);
  const activeTab = useAgentHubStore((s) => s.activeTab);
  const setActiveTab = useAgentHubStore((s) => s.setActiveTab);
  const updateAgent = useUpdateAgent(effectivePath ?? '');

  if (!effectivePath) return <NoAgentSelected />;
  if (!agent) return <AgentNotFound path={effectivePath} />;

  const handleUpdate = (updates: Partial<AgentManifest>) => {
    updateAgent.mutate(updates);
  };

  const handlePersonalityUpdate = (
    updates: Partial<AgentManifest> & { soulContent?: string; nopeContent?: string }
  ) => {
    updateAgent.mutate(updates);
  };

  return (
    <AgentHubProvider
      value={{
        agent,
        projectPath: effectivePath,
        onUpdate: handleUpdate,
        onPersonalityUpdate: handlePersonalityUpdate,
      }}
    >
      <div className="flex h-full flex-col">
        <AgentHubHeader agent={agent} projectPath={effectivePath} />
        <div className="flex min-h-0 flex-1">
          <AgentHubNav activeTab={activeTab} onTabChange={setActiveTab} />
          <AgentHubContent activeTab={activeTab} />
        </div>
      </div>
    </AgentHubProvider>
  );
}
```

NOTE: Verify the exact signature of `useCurrentAgent` and `useUpdateAgent` from `@/layers/entities/agent` before implementing. The agent entity module's public API should be checked via its barrel `index.ts`.

