## Component: AgentHubNav.tsx

Create `apps/client/src/layers/features/agent-hub/ui/AgentHubNav.tsx`:

A left-nav tab list with six tabs (Overview, Personality, Sessions, Channels, Tasks, Tools). Uses icon + label for each tab. Active tab is highlighted.

```typescript
import { cn } from '@/layers/shared/lib';
import {
  User,
  Sparkles,
  MessageSquare,
  Radio,
  Clock,
  Wrench,
  type LucideIcon,
} from 'lucide-react';
import type { AgentHubTab } from '../model/agent-hub-store';

interface AgentHubNavProps {
  activeTab: AgentHubTab;
  onTabChange: (tab: AgentHubTab) => void;
}

interface NavItem {
  id: AgentHubTab;
  label: string;
  icon: LucideIcon;
}

const NAV_ITEMS: NavItem[] = [
  { id: 'overview', label: 'Overview', icon: User },
  { id: 'personality', label: 'Personality', icon: Sparkles },
  { id: 'sessions', label: 'Sessions', icon: MessageSquare },
  { id: 'channels', label: 'Channels', icon: Radio },
  { id: 'tasks', label: 'Tasks', icon: Clock },
  { id: 'tools', label: 'Tools', icon: Wrench },
];

export function AgentHubNav({ activeTab, onTabChange }: AgentHubNavProps) {
  return (
    <nav
      className="flex w-36 shrink-0 flex-col gap-0.5 border-r p-2"
      aria-label="Agent hub navigation"
    >
      {NAV_ITEMS.map((item) => {
        const Icon = item.icon;
        const isActive = activeTab === item.id;
        return (
          <button
            key={item.id}
            type="button"
            onClick={() => onTabChange(item.id)}
            className={cn(
              'flex items-center gap-2 rounded-md px-2 py-1.5 text-sm transition-colors',
              isActive
                ? 'bg-accent text-accent-foreground font-medium'
                : 'text-muted-foreground hover:bg-accent/50 hover:text-foreground'
            )}
            aria-current={isActive ? 'page' : undefined}
          >
            <Icon className="size-4 shrink-0" />
            <span className="truncate">{item.label}</span>
          </button>
        );
      })}
    </nav>
  );
}
```

