import { Suspense, lazy } from 'react';
import type { AgentHubTab } from '../model/agent-hub-store';

// Lazy-load tab content to minimize initial bundle
const OverviewTab = lazy(() => import('./tabs/OverviewTab').then((m) => ({ default: m.OverviewTab })));
const PersonalityTab = lazy(() => import('./tabs/PersonalityTab').then((m) => ({ default: m.PersonalityTab })));
const SessionsTab = lazy(() => import('./tabs/SessionsTab').then((m) => ({ default: m.SessionsTab })));
const ChannelsTab = lazy(() => import('./tabs/ChannelsTab').then((m) => ({ default: m.ChannelsTab })));
const TasksTab = lazy(() => import('./tabs/TasksTab').then((m) => ({ default: m.TasksTab })));
const ToolsTab = lazy(() => import('./tabs/ToolsTab').then((m) => ({ default: m.ToolsTab })));

const TAB_COMPONENTS: Record<AgentHubTab, React.LazyExoticComponent<React.ComponentType>> = {
  overview: OverviewTab,
  personality: PersonalityTab,
  sessions: SessionsTab,
  channels: ChannelsTab,
  tasks: TasksTab,
  tools: ToolsTab,
};

interface AgentHubContentProps {
  activeTab: AgentHubTab;
}

export function AgentHubContent({ activeTab }: AgentHubContentProps) {
  const TabComponent = TAB_COMPONENTS[activeTab];

  return (
    <div className="flex-1 overflow-y-auto">
      <Suspense fallback={null}>
        <TabComponent />
      </Suspense>
    </div>
  );
}
```

