## New Hook: useAgentHubDeepLink

Create `apps/client/src/layers/features/agent-hub/model/use-agent-hub-deep-link.ts`:

```typescript
import { useSearch } from '@tanstack/react-router';
import type { AgentHubTab } from './agent-hub-store';

const VALID_HUB_TABS: AgentHubTab[] = [
  'overview', 'personality', 'sessions', 'channels', 'tasks', 'tools',
];

/**
 * Reads Agent Hub deep-link parameters from URL search params.
 *
 * @returns The hub tab and agent path from the URL, or null if not present.
 */
export function useAgentHubDeepLink(): {
  hubTab: AgentHubTab | null;
  agentPath: string | null;
} {
  const search = useSearch({ strict: false }) as {
    panel?: string;
    hubTab?: string;
    agentPath?: string;
  };

  if (search.panel !== 'agent-hub') {
    return { hubTab: null, agentPath: null };
  }

  const hubTab = VALID_HUB_TABS.includes(search.hubTab as AgentHubTab)
    ? (search.hubTab as AgentHubTab)
    : 'overview';

  return {
    hubTab,
    agentPath: search.agentPath ?? null,
  };
}
```

