```typescript
import { useNavigate, useSearch } from '@tanstack/react-router';
import { useEffect } from 'react';

export function useAgentDialogRedirect() {
  const search = useSearch({ strict: false }) as {
    agent?: string;
    agentPath?: string;
    dialog?: string;
  };
  const navigate = useNavigate();

  useEffect(() => {
    // Redirect old ?agent= params to new ?panel=agent-hub params
    if (search.agent) {
      const TAB_MIGRATION: Record<string, AgentHubTab> = {
        identity: 'overview',
        personality: 'personality',
        channels: 'channels',
        tools: 'tools',
      };
      const hubTab = TAB_MIGRATION[search.agent] ?? 'overview';
      navigate({
        search: (prev: Record<string, string | undefined>) => ({
          ...prev,
          agent: undefined,       // Remove old param
          panel: 'agent-hub',     // New param
          hubTab,
          agentPath: search.agentPath,
        }),
        replace: true,
      } as never);
    }
    // Also redirect ?dialog=agent to ?panel=agent-hub
    if (search.dialog === 'agent') {
      navigate({
        search: (prev: Record<string, string | undefined>) => ({
          ...prev,
          dialog: undefined,
          panel: 'agent-hub',
          hubTab: 'overview',
          agentPath: search.agentPath,
        }),
        replace: true,
      } as never);
    }
  }, [search.agent, search.dialog, search.agentPath, navigate]);
}
```

